"""Frozen contracts for the multi-strategy Planner stage output.

``PlanningStrategy``, ``StrategyComparison``, ``PlanRanking``, and
``PlannerResult`` are the canonical artifacts produced by the Planner
stage in Sprint 3.
"""
from __future__ import annotations

from dataclasses import dataclass, field
from typing import Any


@dataclass(frozen=True)
class PlanningStrategy:
    """A single candidate plan generated by the Planner stage.

    Each strategy represents one distinct approach to answering the
    request (e.g. direct respond, research-then-respond, code-then-respond).
    """

    strategy_id: str
    """Unique identifier for this strategy candidate."""

    name: str
    """Human-readable name (e.g. ``"direct"``, ``"research"``, ``"code"``)."""

    description: str
    """Short description of this strategy's approach."""

    steps: tuple[dict[str, Any], ...] = ()
    """Plan steps for this strategy, same schema as ``context.plan["steps"]``."""

    confidence: float = 0.0
    """Estimated confidence that this strategy will succeed (0–1)."""

    rationale: str = ""
    """Why this strategy was considered (source of generation)."""

    metadata: dict[str, Any] = field(default_factory=dict)
    """Extensible bag for strategy-specific metadata."""


@dataclass(frozen=True)
class StrategyComparison:
    """Result of comparing two planning strategies."""

    winner_id: str
    """``strategy_id`` of the higher-ranked strategy."""

    loser_id: str
    """``strategy_id`` of the lower-ranked strategy."""

    margin: float = 0.0
    """Score difference (0 = tie, >0 = winner ahead)."""

    reasons: tuple[str, ...] = ()
    """Human-readable reasons for this comparison result."""


@dataclass(frozen=True)
class PlanRanking:
    """Ranked list of all candidate strategies.

    ``strategies`` are ordered from best (index 0) to worst.
    """

    strategies: tuple[PlanningStrategy, ...] = ()
    """Candidate strategies sorted by rank (best first)."""

    comparisons: tuple[StrategyComparison, ...] = ()
    """Pairwise comparisons that determined the ranking."""

    selected_id: str = ""
    """``strategy_id`` of the winning strategy."""

    selection_rationale: str = ""
    """Why the winning strategy was selected."""


@dataclass(frozen=True)
class PlannerResult:
    """Canonical output of the multi-strategy Planner stage.

    Replaces the legacy single-plan approach.  ``context.plan`` is
    still populated from the winning strategy for backward compat.
    """

    plan_id: str
    """Unique identifier for this planning pass."""

    ranking: PlanRanking = field(default_factory=PlanRanking)
    """Full ranking of all candidate strategies."""

    selected_strategy: PlanningStrategy | None = None
    """The winning strategy (shortcut for ``ranking.strategies[0]``)."""

    total_candidates: int = 0
    """Number of strategy candidates that were generated."""

    metadata: dict[str, Any] = field(default_factory=dict)
    """Extensible bag for planner-specific metadata."""
